namespace App\Services;

class UserPreferenceService
{
    protected $cookieName = 'user_prefs';

    public function __construct($cookieName = 'user_prefs')
    {
        $this->cookieName = $cookieName;
    }

    public function getPreferences()
    {
        if (isset($_COOKIE[$this->cookieName])) {
            return unserialize($_COOKIE[$this->cookieName]);
        }
        return [];
    }

    public function setPreference($key, $value)
    {
        $preferences = $this->getPreferences();
        if (!is_array($preferences)) {
            $preferences = [];
        }
        $preferences[$key] = $value;
        $this->savePreferences($preferences);
    }

    public function getPreference($key, $default = null)
    {
        $preferences = $this->getPreferences();
        return is_array($preferences) && isset($preferences[$key]) ? $preferences[$key] : $default;
    }

    public function removePreference($key)
    {
        $preferences = $this->getPreferences();
        if (is_array($preferences) && isset($preferences[$key])) {
            unset($preferences[$key]);
            $this->savePreferences($preferences);
        }
    }

    public function clearPreferences()
    {
        setcookie($this->cookieName, '', time() - 3600, '/', '', false, false);
    }

    protected function savePreferences(array $preferences)
    {
        $serialized = serialize($preferences);
        setcookie($this->cookieName, $serialized, time() + 2592000, '/', '', false, false);
    }
}

namespace App\Providers;

use Illuminate\Support\ServiceProvider;
use App\Http\SessionHandlers\CookiePreferenceSessionHandler;
use App\Services\UserPreferenceService;

class PreferenceServiceProvider extends ServiceProvider
{
    public function register()
    {
        $this->app->singleton(UserPreferenceService::class, function ($app) {
            return new UserPreferenceService(config('preferences.cookie_name', 'user_prefs'));
        });
    }

    public function boot()
    {
        $this->app['session']->extend('cookie_preferences', function ($app) {
            return new CookiePreferenceSessionHandler([
                'cookie_name' => config('preferences.cookie_name', 'user_prefs'),
                'lifetime' => config('preferences.lifetime', 2592000),
                'path' => config('preferences.path', '/'),
                'domain' => config('preferences.domain', ''),
                'secure' => config('preferences.secure', false),
                'http_only' => config('preferences.http_only', false),
            ]);
        });
    }
}

namespace App\Http\Middleware;

use Closure;
use Illuminate\Http\Request;
use App\Services\UserPreferenceService;

class LoadUserPreferences
{
    protected $preferenceService;

    public function __construct(UserPreferenceService $preferenceService)
    {
        $this->preferenceService = $preferenceService;
    }

    public function handle(Request $request, Closure $next)
    {
        $preferences = $this->preferenceService->getPreferences();
        
        if (is_array($preferences)) {
            $request->merge(['user_preferences' => $preferences]);
        }

        return $next($request);
    }
}

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use App\Services\UserPreferenceService;

class PreferenceController
{
    protected $preferenceService;

    public function __construct(UserPreferenceService $preferenceService)
    {
        $this->preferenceService = $preferenceService;
    }

    public function index()
    {
        $preferences = $this->preferenceService->getPreferences();
        return response()->json(['preferences' => $preferences]);
    }

    public function store(Request $request)
    {
        $key = $request->input('key');
        $value = $request->input('value');
        
        $this->preferenceService->setPreference($key, $value);
        
        return response()->json(['success' => true, 'message' => 'Preference saved']);
    }

    public function update(Request $request)
    {
        $preferences = $request->input('preferences', []);
        
        foreach ($preferences as $key => $value) {
            $this->preferenceService->setPreference($key, $value);
        }
        
        return response()->json(['success' => true, 'message' => 'Preferences updated']);
    }

    public function destroy($key)
    {
        $this->preferenceService->removePreference($key);
        return response()->json(['success' => true, 'message' => 'Preference removed']);
    }

    public function clear()
    {
        $this->preferenceService->clearPreferences();
        return response()->json(['success' => true, 'message' => 'All preferences cleared']);
    }
}